INSERT INTO "public"."loss_event" ("loss_event_id", "type", "sub_type", "label", "description") VALUES
	('LEV-0001', 'natural', 'earthquake', 'Earthquake in Christchurch', 'In December 2018 an earthquake with magnitude 6.2 struck the Christchurch region, causing structural damage to commercial and residential properties within a 50 km radius.'),
	('LEV-0002', 'natural', 'flood', 'Bangkok industrial estate floods', 'Prolonged monsoon rainfall led to river overflow affecting several industrial estates on the outskirts of Bangkok, inundating warehouses and production plants for multiple weeks.'),
	('LEV-0003', 'manmade', 'fire', 'Hamburg distribution centre fire', 'A large fire broke out in a logistics distribution centre near the Port of Hamburg, originating in a battery storage area and spreading through adjoining warehouse units.'),
	('LEV-0004', 'manmade', 'explosion', 'Chemical plant explosion in Rotterdam', 'An overpressure incident in a storage tank triggered an explosion at a chemical plant in the Rotterdam harbour area, resulting in damage to nearby buildings and infrastructure.'),
	('LEV-0005', 'natural', 'windstorm', 'European windstorm “Klara”', 'A deep low-pressure system tracked across Western and Central Europe, generating severe wind gusts and localised power outages, with roof damage across multiple urban centres.'),
	('LEV-0006', 'natural', 'hail', 'Sydney supercell hailstorm', 'A severe convective storm system produced large hailstones across Sydney suburbs, denting vehicle fleets, damaging skylights and solar panels, and breaking glazing.'),
	('LEV-0007', 'manmade', 'riot', 'City centre civil unrest', 'Extended civil unrest in the city centre resulted in vandalism, looting, and fire damage to multiple retail and hospitality locations along the main commercial streets.'),
	('LEV-0008', 'manmade', 'cyber', 'Ransomware attack on logistics operator', 'A coordinated ransomware attack encrypted key logistics and booking systems, forcing manual operations and causing significant business interruption losses across several depots.'),
	('le_meteorological', 'Peril', 'Meteorological Peril', 'Meteorological Peril', 'Weather-related events including storms, hurricanes, floods, hail'),
	('le_geological', 'Peril', 'Geological Peril', 'Geological Peril', 'Earth-related events including earthquakes, volcanic eruptions, landslides'),
	('le_fire', 'Peril', 'Fire', 'Fire', 'Fire and explosion events'),
	('le_water_damage', 'Peril', 'Water Damage', 'Water Damage', 'Water damage from non-weather sources'),
	('le_theft', 'Liability', 'Theft', 'Theft', 'Theft and burglary'),
	('le_third_party', 'Liability', 'Third Party', 'Third Party Liability', 'Third party liability claims'),
	('le_property_damage', 'Property', 'Property Damage', 'Property Damage', 'Direct property damage'),
	('le_business_interruption', 'Property', 'Business Interruption', 'Business Interruption', 'Loss of business income'),
	('le_cyber', 'Cyber', 'Cyber Attack', 'Cyber Attack', 'Cyber security incidents and data breaches'),
	('le_other', 'Other', 'Other', 'Other', 'Other types of losses');
